function LxWorldHandler:OnWorldCityMoveResp(pb)
    --- 请求结果 0：成功  其他失败
    local position = pb.position
    local force = pb.force
    if position then
        ModuleCenter.Role:SetGridPos(position.X, position.Z)
        ModuleCenter.World:SetMyGridPos(position.X, position.Z)
        if not MgrCenter.LevelMgr:IsInLevel(LevelNames.World) then
            CtrlCenter.World:GoWorld({
                gridX = position.X,
                gridZ = position.Z
            })
        end
    end
    if force then --// 是否被强迁、被打爆、被打飞
        ShowPanel(UiNames.Alert, {refId = 7008})
    end
end

