function LxWorldHandler:OnMarchUpdateResp(pb)
    local updateMarchIds = pb.updateMarchIds
    local deleteMarchIds = pb.deleteMarchIds
    if deleteMarchIds then
        ModuleCenter.World:RemoveMarchList(deleteMarchIds)
    end
    if updateMarchIds then
        local marchMap = ModuleCenter.World:GetMarchDataMap() or {}
        for _, marchId in ipairs(updateMarchIds) do
            if not marchMap[marchId] or ModuleCenter.World:IsMarchOutView(marchId) then
                self:MarchListReq()
                break
            end
        end
    end
end

