---部队行军（移动）请求
function LxWorldHandler:MarchMoveReq(params)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MarchMoveReq)
    -- formation
    proto.formation.formationIndex = 0
    for _, heroId in ipairs(params.heroIds) do
        table.insert(proto.formation.heroIds, heroId)
    end
    for _, soldierItem in ipairs(params.soldiers) do
        if soldierItem.value > 0 then
            local kv = proto.formation.soldiers:add()
            kv.key = soldierItem.key
            kv.value = soldierItem.value
        end
    end
    --- targetPos
    proto.targetPos.X = params.gridX
    proto.targetPos.Z = params.gridZ
    proto.targetType = params.targetType
    proto.targetId = params.targetId
    proto.action = params.action
    --- 战斗玩法ID，combatSlg-战斗玩法配置表中的ID
    proto.actionRef = params.actionRef
    if params.watchTowerEventId then
        proto.watchTowerEventId = params.watchTowerEventId
    end

    if params.waitTime ~= nil then
        proto.waitTime = params.waitTime
    end

    if params.hideCamp ~= nil then
        proto.hideCamp = params.hideCamp
    end

    SendMessage(LxProtoIds.MarchMoveReq, proto)
end

