---行军士兵容量请求
function LxWorldHandler:MarchFormationCalcReq(action, formationObj, slgCombatId, gridX, gridZ)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MarchFormationCalcReq)
    -- formation
    proto.formation.formationIndex = 0
    for _, heroId in ipairs(formationObj.heroIds) do
        table.insert(proto.formation.heroIds, heroId)
    end
    for _, soldierItem in pairs(formationObj.soldierMap) do
        if soldierItem.value > 0 then
            local kv = proto.formation.soldiers:add()
            kv.key = soldierItem.key
            kv.value = soldierItem.value
        end
    end
    proto.action = action
    if slgCombatId then
        proto.actionRef = slgCombatId
    end
    if gridX and gridZ then
        proto.to.X = gridX
        proto.to.Z = gridZ
    end
    SendMessage(LxProtoIds.MarchFormationCalcReq, proto)
end
