---援军信息返回
function LxWorldHandler:OnMarchAssistInfoResp(pb)
    local roleId = pb.roleId
    if roleId then
        local selfRole = ModuleCenter.Login:IsSelf(roleId)
        if selfRole then
            ModuleCenter.World:SetMarchAssistData(pb)
            FireEvent(EventNames.REFRESH_EMBASSYASSISTLIST)
        else
            ModuleCenter.World:SetOtherMarchAssistData(pb)
        end
        FireEvent(EventNames.REFRESH_EMBASSYASSISTLISTINFO)
    end
end

---援军遣返返回
function LxWorldHandler:OnMarchAssistRepatriateResp(pb)
    local marchIds = pb.marchIds --援军队列id
    if marchIds then
        for _,marchId in ipairs(marchIds) do
            ModuleCenter.World:DeleteMarchAssist(marchId)
            ModuleCenter.World:DeleteOtherMarchAssist(marchId)
        end
        FireEvent(EventNames.REFRESH_EMBASSYASSISTLIST)
    end

end

