function LxWorldHandler:OnMarchAssistUpdateResp(pb)
    ModuleCenter.World:SetMarchAssistData(pb)
    FireEvent(EventNames.REFRESH_EMBASSYASSISTLIST)
    FireEvent(EventNames.REFRESH_EMBASSYUPDATEASSIST)
end

---援军删除返回
function LxWorldHandler:OnMarchAssistDeleteResp(pb)
    local marchIds = pb.marchIds --援军队列id
    if marchIds then
        for _, marchId in ipairs(marchIds) do
            ModuleCenter.World:DeleteMarchAssist(marchId)
        end
        FireEvent(EventNames.REFRESH_EMBASSYASSISTLIST)
        FireEvent(EventNames.EFRESH_EMBASSYREMOVEASSIST)
    end
end

---援军请求援军返回
function LxWorldHandler:OnMarchAssistHelpResp(pb)
    if pb.type then
        ShowSysMsg(I18nText(9505))
    end
end

function LxWorldHandler:OnWorldSummonMonsterGenerateResp(pb)
    local coord = pb.coord
    if coord then
        local gridX = coord.X
        local gridZ = coord.Z
        CtrlCenter.World:GoWorld({ gridX = gridX, gridZ = gridZ, time = 0.3 , callback = function()
            CtrlCenter.World:CheckOpenEntityMenuByPos(gridX, gridZ)
        end})
    end
end

-------------------------------------------------------------------------------------------
return LxWorldHandler